mapper.select:
SELECT , pi.path AS image_path FROM posts p LEFT JOIN post_images pi ON p.id = pi.post_id AND pi.sort_order = 0
WHERE p.id < #{lastId}
ORDER BY p.created_at DESC, p.id DESC LIMIT #{size}

SELECT , pi.path AS image_path FROM posts p LEFT JOIN post_images pi ON p.id = pi.post_id AND pi.sort_order = 0 WHERE p.caption LIKE CONCAT('%', #{keyword}, '%')
AND p.id < #{lastId}
ORDER BY p.created_at DESC, p.id DESC LIMIT #{size}
